proof_block:
// `cack_state_swap`'s only ensures is a single `HashMap::swap_spec` call;
// the synthetic ensures here is `(H1 && H2) ==> det_..._equal(...)` with
// H_i the swap_spec for run i. We bring the two hypotheses into scope with
// a single `if` and then re-derive each conjunct of `det_..._equal`. Every
// assertion below is *checked* by Verus under (H1 && H2): we are not
// admitting anything, we are just lining up the triggers from the two
// `swap_spec` instances so z3 picks the same `Map::insert` term for both.
//
//   swap_spec  ==  put_spec ∧ match get_spec ...
//
// `put_spec(old, new, k, v)` is the `pub open spec` body
//     `new == old.insert(k, v)`,
// so both `post*_self_.epmap@` collapse to the *same* term
//     `pre_self_.epmap@.insert(src@, pre_ack_state)`.
// The `match get_spec(...)` arm pins both `post*_ack_state` to the same
// witness (`Some(v) -> v`, `None -> default`), giving full `CAckState`
// equality and therefore per-field equality on `num_packets_acked`/`un_acked`.
// `r1` and `r2` are both `()`, so `r1 == r2` is automatic.
if HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
    && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default) {

    // Step 1: unfold `put_spec` for each run to obtain the same `Map::insert` term.
    assert(post1_self_.epmap@ == pre_self_.epmap@.insert(src@, pre_ack_state));
    assert(post2_self_.epmap@ == pre_self_.epmap@.insert(src@, pre_ack_state));

    // Step 2: lift the shared insert term to view-equality on epmap, both via
    // `==` (direct transitivity) and via `=~=` (Map extensionality), so z3 has
    // both flavors available no matter which trigger fires.
    assert(post1_self_.epmap@ == post2_self_.epmap@);
    assert(post1_self_.epmap@ =~= post2_self_.epmap@);

    // Step 3: from the `match get_spec(pre_self_.epmap@, src@)` arm shared by
    // both swap_specs, both `post*_ack_state` are equal to the same witness.
    assert(post1_ack_state == post2_ack_state);

    // Step 4: per-field consequences that `det_cack_state_swap_equal` checks.
    assert(post1_ack_state.num_packets_acked == post2_ack_state.num_packets_acked);
    assert(post1_ack_state.un_acked == post2_ack_state.un_acked);

    // Step 5: unit-type equality. Both r1 and r2 have type `()`.
    assert(r1 == r2);
}
